        # Safely convert to float
        bill_amount = float(inputs["bill_amount"])

        # Handle tip_percentage (default to 0.0 if not provided)
        tip_percentage = float(inputs.get("tip_percentage", 0.0))

    except (ValueError, TypeError):
        return {
            "error": "Invalid Input: Please provide valid numbers for inputs",
            **fallback_results
