  "script_content": "def calculate(inputs: dict) -> dict:
    # Default result structure with fallback values
    results = {
        "total_payment": 0.0,
        "total_interest": 0.0
    }

    try:
        # 1. Extract and cast numerical values
        if "loan_amount" not in inputs or inputs["loan_amount"] is None:
            return {"error": "Missing loan amount.", **results}
        loan_amount = float(inputs["loan_amount"])
        if loan_amount <= 0:
            return {"error": "Invalid Input: Loan amount must be greater than 0.", **results}

        if "interest_rate" not in inputs or inputs["interest_rate"] is None:
            return {"error": "Missing interest rate.", **results}
        interest_rate = float(inputs["interest_rate"])
        if interest_rate < 0:
            return {"error": "Invalid Input: Interest rate cannot be negative.", **results}

        if "loan_term_years" not in inputs or inputs["loan_term_years"] is None:
            return {"error": "Missing loan term.", **results}
        loan_term_years = float(inputs["loan_term_years"])
        if loan_term_years <= 0:
            return {"error": "Invalid Input: Loan term must be greater than 0.", **results}

        # 2. Extract and resolve compounding frequency
        freq_input = inputs.get("compounding_frequency")
        if isinstance(freq_input, list):
            if len(freq_input) > 0:
                freq = freq_input[0]
            else:
                return {"error": "Please select a compounding frequency.", **results}
        else:
            freq = freq_input

        if not freq:
            return {"error": "Please select a compounding frequency.", **results}

        freq_mapping = {
            "monthly": 12,
            "quarterly": 4,
            "annually": 1
        }

        freq_str = str(freq).lower().strip()
        if freq_str not in freq_mapping:
            return {"error": f"Invalid compounding frequency: {freq}", **results}

        n = freq_mapping[freq_str]

        # 3. Perform calculations
        r = interest_rate / 100.0
        total_payment = loan_amount * ((1 + r / n) ** (n * loan_term_years))
        total_interest = total_payment - loan_amount

        # 4. Populate rounded outputs
        results["total_payment"] = round(total_payment, 2)
        results["total_interest"] = round(total_interest, 2)
        return results

    except Exception as e:
        return {"error": f"An error occurred during calculation: {str(e)}", **results}
